	private static int CompareEntries(InventoryEntry a, InventoryEntry b)
	{
		if (a.IsWallet != b.IsWallet)
		{
			if (!a.IsWallet)
			{
				return 1;
			}
			return -1;
		}
		if (a.IsExpired != b.IsExpired)
		{
			if (!a.IsExpired)
			{
				return -1;
			}
			return 1;
		}
		return string.Compare(a.Title, b.Title, StringComparison.OrdinalIgnoreCase);
	}

	private List<InventoryEntry> BuildEntries(PubgEventInventoryStateMessage state)
	{
		List<InventoryEntry> list = new List<InventoryEntry>(state.Assets.Count + state.Wallets.Count);
		foreach (PubgEventWalletInfo wallet in state.Wallets)
		{
			if (wallet.Balance > 0)
			{
				string title = ResolveWalletTitle(wallet.WalletKey);
				string description = ResolveWalletDescription(wallet.WalletKey);
				list.Add(new InventoryEntry(wallet.WalletKey, title, description, wallet.WalletKey, Loc.GetString("pubg-events-inventory-type-wallet"), ResolveWalletIconPath(wallet.WalletKey), wallet.Balance, IsExpired: false, IsWallet: true));
			}
		}
		foreach (PubgEventInventoryAssetInfo asset in state.Assets)
		{
			if (asset.Quantity > 0)
			{
				string title2 = ResolveLoc(asset.TitleKey, asset.AssetKey);
				string description2 = ResolveAssetDescription(asset);
				string typeLabel = ResolveAssetTypeLabel(asset.AssetType);
				list.Add(new InventoryEntry(asset.AssetKey, title2, description2, asset.AssetType, typeLabel, asset.IconPath, asset.Quantity, asset.IsExpired, IsWallet: false));
			}
		}
		return list;
	}

